@page "/"
@attribute [Authorize]
@inject ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1 class="mb-4">Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments.Count</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="card-text display-6">@totalPets</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidInvoices</p>
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-6">
        <h3>Today's Appointments</h3>
        @if (todayAppointments.Any())
        {
            <table class="table table-striped">
                <thead>
                    <tr><th>Time</th><th>Pet</th><th>Reason</th><th>Status</th></tr>
                </thead>
                <tbody>
                    @foreach (var apt in todayAppointments)
                    {
                        <tr>
                            <td>@apt.ScheduledAt.ToString("HH:mm")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.Status</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No appointments scheduled for today.</p>
        }
    </div>
    <div class="col-md-6">
        <h3>Recent Patients</h3>
        @if (recentPets.Any())
        {
            <table class="table table-striped">
                <thead>
                    <tr><th>Name</th><th>Species</th><th>Owner</th></tr>
                </thead>
                <tbody>
                    @foreach (var pet in recentPets)
                    {
                        <tr>
                            <td><a href="patients/@pet.Id">@pet.Name</a></td>
                            <td>@pet.Species</td>
                            <td>@pet.Owner.FullName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No patients registered yet.</p>
        }
    </div>
</div>

@code {
    private List<Appointment> todayAppointments = new();
    private List<Pet> recentPets = new();
    private int totalPets;
    private int unpaidInvoices;

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        todayAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt.Date == today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();

        recentPets = await Db.Pets
