@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav
@using Microsoft.EntityFrameworkCore

<PageTitle>Appointments</PageTitle>

<h1 class="mb-4">Appointments</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <button class="btn btn-outline-secondary" @onclick="PrevWeek">&laquo; Previous</button>
        <span class="mx-3 fw-bold">@weekStart.ToString("MMM dd") - @weekEnd.ToString("MMM dd, yyyy")</span>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
    </div>
    <a href="appointments/create" class="btn btn-primary">New Appointment</a>
</div>

<div class="table-responsive mb-4">
    <table class="table table-bordered table-sm">
        <thead>
            <tr>
                <th>Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center @(day.Date == DateTime.Today ? "table-info" : "")">
                        @day.ToString("ddd MM/dd")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour <= 17; hour++)
            {
                <tr>
                    <td class="fw-bold">@($"{hour:00}:00")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotTime = day.AddHours(hour);
                        var slotAppointments = weekAppointments
                            .Where(a => a.ScheduledAt.Date == day.Date && a.ScheduledAt.Hour == hour)
                            .ToList();

                        if (slotAppointments.Any())
                        {
                            <td class="table-warning text-center">
                                @foreach (var apt in slotAppointments)
                                {
                                    <small>@apt.Pet.Name</small><br />
                                }
                            </td>
                        }
                        else
                        {
                            <td class="text-center text-muted">
                                <a href="appointments/create" class="text-decoration-none text-muted">+</a>
                            </td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

<h3>This Week's Appointments</h3>
@if (weekAppointments.Any())
{
    <table class="table table-striped">
        <thead>
            <tr><th>Date/Time</th><th>Pet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var apt in weekAppointments.OrderBy(a => a.ScheduledAt))
            {
                <tr>
                    <td>@apt.ScheduledAt.ToString("ddd MM/dd HH:mm")</td>
                    <td>@apt.Pet.Name</td>
                    <td>@apt.Reason</td>
                    <td>
                        <span class="badge @GetStatusBadge(apt.Status)">@apt.Status</span>
                    </td>
                    <td>
                        @if (apt.Status == AppointmentStatus.Scheduled)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt)">Cancel</button>
                            <button class="btn btn-sm btn-outline-success" @onclick="() => CompleteAppointment(apt)">Complete</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No appointments this week.</p>
}

@code {
    private DateTime weekStart;
    private DateTime weekEnd;
    private List<Appointment> weekAppointments = new();

    protected override async Task OnInitializedAsync()
    {
        SetCurrentWeek(DateTime.Today);
        await LoadAppointments();
    }

    private void SetCurrentWeek(DateTime date)
    {
        int diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        weekStart = date.AddDays(-diff).Date;
        weekEnd = weekStart.AddDays(6);
    }

    private async Task LoadAppointments()
    {
        weekAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt.Date >= weekStart && a.ScheduledAt.Date <= weekEnd)
            .ToListAsync();
    }

    private async Task PrevWeek()
    {
        weekStart = weekStart.AddDays(-7);
        weekEnd = weekEnd.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        weekEnd = weekEnd.AddDays(7);
        await LoadAppointments();
    }

    private async Task CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
    }

    private async Task CompleteAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

