            </InputSelect>
        </div>
        <div class="col-md-6">
            <label class="form-label">Due Date</label>
            <InputDate class="form-control" @bind-Value="model.DueDate" />
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table">
        <thead>
            <tr>
                <th>Description</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Line Total</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @for (int i = 0; i < model.Items.Count; i++)
            {
