                <tr>
                    <td>
                        <InputText class="form-control" @bind-Value="model.Items[index].Description" />
                    </td>
                    <td style="width:100px">
                        <InputNumber class="form-control" @bind-Value="model.Items[index].Quantity" />
                    </td>
                    <td style="width:120px">
                        <InputNumber class="form-control" @bind-Value="model.Items[index].UnitPrice" />
                    </td>
                    <td style="width:120px">
                        @((model.Items[index].Quantity * model.Items[index].UnitPrice).ToString("C"))
                    </td>
                    <td>
                        <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItem(index)">✕</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddItem">+ Add Line Item</button>

    <div class="mb-3">
        <strong>Total: @ComputeTotal().ToString("C")</strong>
    </div>

    <button type="submit" class="btn btn-primary">Create Invoice</button>
    <a href="billing" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private InvoiceModel model = new();
    private List<Pet>? pets;

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        model.DueDate = DateTime.Today.AddDays(30);
        model.Items.Add(new LineItemModel());
    }

    private void AddItem()
    {
        model.Items.Add(new LineItemModel());
    }

    private void RemoveItem(int index)
    {
        if (model.Items.Count > 1)
            model.Items.RemoveAt(index);
    }

    private decimal ComputeTotal() => model.Items.Sum(i => i.Quantity * i.UnitPrice);

    private async Task HandleSubmit()
    {
        if (model.PetId == 0) return;

        var invoice = new Invoice
        {
            PetId = model.PetId,
            CreatedAt = DateTime.Now,
            DueDate = model.DueDate,
            TotalAmount = ComputeTotal(),
            IsPaid = false
        };

        foreach (var item in model.Items)
        {
            invoice.Items.Add(new InvoiceLineItem
            {
                Description = item.Description,
                Quantity = item.Quantity,
                UnitPrice = item.UnitPrice,
                LineTotal = item.Quantity * item.UnitPrice
            });
        }

        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        Nav.NavigateTo("billing");
    }

    private class InvoiceModel
    {
        [Range(1, int.MaxValue)]
        public int PetId { get; set; }
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(30);
        public List<LineItemModel> Items { get; set; } = new();
    }

    private class LineItemModel
    {
        public string Description { get; set; } = string.Empty;
        public int Quantity { get; set; } = 1;
        public decimal UnitPrice { get; set; }
    }
}

@page "/billing/{Id:int}"
@attribute [Authorize]
@inject ApplicationDbContext Db
@using Microsoft.EntityFrameworkCore

<PageTitle>Invoice Details</PageTitle>

@if (invoice is null)
{
    <p>Loading...</p>
}
else
{
    <h1 class="mb-4">Invoice #@invoice.Id</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <p><strong>Pet:</strong> @invoice.Pet.Name</p>
            <p><strong>Created:</strong> @invoice.CreatedAt.ToString("yyyy-MM-dd")</p>
            <p><strong>Due Date:</strong> @invoice.DueDate.ToString("yyyy-MM-dd")</p>
            <p><strong>Status:</strong>
                @if (invoice.IsPaid)
                {
                    <span class="badge bg-success">Paid</span>
                }
                else
                {
                    <span class="badge bg-warning text-dark">Unpaid</span>
                }
            </p>
        </div>
        <div class="col-md-6 text-end">
            <h3>Total: @invoice.TotalAmount.ToString("C")</h3>
            <p>Paid: @invoice.Payments.Sum(p => p.Amount).ToString("C")</p>
            <p>Balance: @((invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount)).ToString("C"))</p>
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table table-striped mb-4">
        <thead>
            <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th></tr>
        </thead>
        <tbody>
            @foreach (var item in invoice.Items)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>@item.UnitPrice.ToString("C")</td>
                    <td>@item.LineTotal.ToString("C")</td>
                </tr>
            }
        </tbody>
    </table>

    <h4>Payments</h4>
    @if (invoice.Payments.Any())
    {
        <table class="table table-striped mb-4">
            <thead>
                <tr><th>Date</th><th>Amount</th><th>Method</th></tr>
            </thead>
            <tbody>
                @foreach (var payment in invoice.Payments.OrderBy(p => p.PaidAt))
                {
                    <tr>
                        <td>@payment.PaidAt.ToString("yyyy-MM-dd HH:mm")</td>
                        <td>@payment.Amount.ToString("C")</td>
                        <td>@payment.Method</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }

    @if (!invoice.IsPaid)
    {
        <div class="card">
            <div class="card-header"><h5>Process Payment</h5></div>
            <div class="card-body">
                <EditForm Model="paymentModel" OnValidSubmit="ProcessPayment" FormName="ProcessPayment">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-4">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="paymentModel.Amount" />
                            <ValidationMessage For="() => paymentModel.Amount" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentModel.Method">
                                @foreach (var method in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@method">@method</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-4 d-flex align-items-end">
                            <button type="submit" class="btn btn-success">Record Payment</button>
                        </div>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    <div class="mt-3">
        <a href="billing" class="btn btn-secondary">Back to Billing</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private PaymentModel paymentModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);

        if (invoice is not null)
        {
            paymentModel.Amount = invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount);
        }
    }

    private async Task ProcessPayment()
    {
        if (invoice is null) return;

        var payment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = paymentModel.Amount,
            PaidAt = DateTime.Now,
            Method = paymentModel.Method
        };

        Db.Payments.Add(payment);

        var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
        if (totalPaid >= invoice.TotalAmount)
        {
            invoice.IsPaid = true;
        }

        await Db.SaveChangesAsync();
        await LoadInvoice();
        paymentModel = new PaymentModel { Amount = invoice!.TotalAmount - invoice.Payments.Sum(p => p.Amount) };
    }

    private class PaymentModel
    {
        [Range(0.01, double.MaxValue, ErrorMessage = "Amount must be greater than 0")]
        public decimal Amount { get; set; }
        public PaymentMethod Method { get; set; } = PaymentMethod.Cash;
    }
}

